     1→import {
     2→  NavigationProp,
     3→  useFocusEffect,
     4→  useNavigation,
     5→} from '@react-navigation/native';
     6→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
     7→import { format, parseISO } from 'date-fns';
     8→import React, { useMemo, useRef, useState } from 'react';
     9→import { Dimensions } from 'react-native';
    10→import { PropsRootStack } from 'src/routes/Models';
    11→import { useShallow } from 'zustand/react/shallow';
    12→import { eventScreenViewV3, eventSelectContent } from '~/constants/functions';
    13→import { useRootStore } from '~/store';
    14→import { PointsExtractStatus } from '../../services/models';
    15→import { getPointsExtract } from '../../services/services';
    16→import { FilterGroup } from '../ExtractRewardProgram/Models';
    17→import MyOrdersCashbackView from './view';
    18→
    19→const MyOrdersCashback = () => {
    20→  const [isRefreshing, setIsRefreshing] = useState(false);
    21→
    22→  const modalizeRefFilters = useRef<PropsModalizeRef>(null);
    23→  const emptyImage =
    24→    'https://image.mkt-semparar.com.br/lib/fe2f117170640475721171/m/1/shopping_cart.png';
    25→
    26→  const SKELETON_COUNT = 3;
    27→  const { width } = Dimensions.get('window');
    28→
    29→  const { pointsExtract, pointsExtractActions } = useRootStore(
    30→    useShallow(state => ({
    31→      pointsExtract: state.pointsExtract,
    32→      pointsExtractActions: state.pointsExtractActions,
    33→    })),
    34→  );
    35→
    36→  const getFormatDate = (iso?: string) => {
    37→    if (!iso) return '';
    38→    const date = parseISO(iso);
    39→    return format(date, 'dd/MM/yyyy');
    40→  };
    41→
    42→  const getFilterGroups: FilterGroup[] = useMemo(() => {
    43→    return [
    44→      {
    45→        label: 'Períodos',
    46→        options: [
    47→          {
    48→            label: '7 dias',
    49→            value: 0,
    50→          },
    51→          {
    52→            label: '15 dias',
    53→            value: 1,
    54→          },
    55→          {
    56→            label: '30 dias',
    57→            value: 2,
    58→          },
    59→          {
    60→            label: '60 dias',
    61→            value: 3,
    62→          },
    63→          {
    64→            label: '90 dias',
    65→            value: 4,
    66→          },
    67→        ],
    68→      },
    69→      {
    70→        label: 'Tipos de lançamentos',
    71→        options: [
    72→          {
    73→            label: 'Mais recentes',
    74→            value: 'ASC',
    75→          },
    76→          {
    77→            label: 'Mais antigas',
    78→            value: 'DESC',
    79→          },
    80→        ],
    81→      },
    82→    ];
    83→  }, []);
    84→
    85→  const handleOpenFilters = () => {
    86→    eventSelectContent({
    87→      content_type: 'cta',
    88→      content_id: 'filtro_pedidos',
    89→      location_1: 'monetizacao',
    90→      location_2: 'hub_recompensas_spmais',
    91→      location_3: 'meus_pedidos',
    92→    });
    93→
    94→    modalizeRefFilters.current?.open?.();
    95→  };
    96→
    97→  const handleDetailsOrders = () => {
    98→    eventSelectContent({
    99→      content_type: 'cta',
   100→      content_id: 'detalhe_pedido',
   101→      location_1: 'monetizacao',
   102→      location_2: 'hub_recompensas_spmais',
   103→      location_3: 'meus_pedidos',
   104→    });
   105→  };
   106→
   107→  const myOrders = pointsExtract?.extractData?.transactions || [];
   108→
   109→  const isLoading = pointsExtract.status === PointsExtractStatus.LOADING;
   110→  const isError = pointsExtract.status === PointsExtractStatus.ERROR;
   111→
   112→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
   113→
   114→  const handleGoBack = () => {
   115→    pointsExtractActions.clearTransactionsFilters();
   116→    pointsExtractActions.reset();
   117→    navigation.goBack();
   118→  };
   119→
   120→  const handleRefresh = async () => {
   121→    setIsRefreshing(true);
   122→    await getPointsExtract({ type: 'Resgate' });
   123→    setIsRefreshing(false);
   124→  };
   125→
   126→  const hasFocused = useRef(false);
   127→  useFocusEffect(
   128→    React.useCallback(() => {
   129→      if (!hasFocused.current) {
   130→        eventScreenViewV3(
   131→          'meus_pedidos',
   132→          'hub_recompensas_spmais',
   133→          'monetizacao',
   134→          {
   135→            location_1: 'monetizacao',
   136→            location_2: 'hub_recompensas_spmais',
   137→            location_3: 'meus_pedidos',
   138→          },
   139→        );
   140→        pointsExtractActions.clearTransactionsFilters();
   141→        pointsExtractActions.reset();
   142→        getPointsExtract({ type: 'Resgate' });
   143→        hasFocused.current = true;
   144→      }
   145→      return () => {
   146→        hasFocused.current = false;
   147→      };
   148→    }, [pointsExtractActions]),
   149→  );
   150→
   151→  return (
   152→    <MyOrdersCashbackView
   153→      myOrders={myOrders}
   154→      emptyImage={emptyImage}
   155→      isLoading={isLoading}
   156→      isError={isError}
   157→      filterGroups={getFilterGroups}
   158→      modalizeRefFilters={modalizeRefFilters}
   159→      formatDate={getFormatDate}
   160→      handleGoBack={handleGoBack}
   161→      handleOpenFilters={handleOpenFilters}
   162→      handleDetailsOrders={handleDetailsOrders}
   163→      isRefreshing={isRefreshing}
   164→      handleRefresh={handleRefresh}
   165→      skeletonCount={SKELETON_COUNT}
   166→      screenWidth={width}
   167→    />
   168→  );
   169→};
   170→
   171→export default MyOrdersCashback;
   172→

