     1→import {
     2→  Box,
     3→  CardVehicleTags,
     4→  Image,
     5→  PropsIconsNameCore,
     6→  Skeleton,
     7→  Text,
     8→} from '@semparar/design-system-app';
     9→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
    10→import theme from '@semparar/design-system-app/src/styles/theme';
    11→import React, { FC, RefObject } from 'react';
    12→import { FlatList, RefreshControl } from 'react-native';
    13→import ApiError from '../../atomic/organisms/ApiError';
    14→import FiltersBottomSheet from '../../atomic/organisms/FiltersBottomSheet';
    15→import BasicScreen from '../../atomic/templates/BasicScreen';
    16→import { MyOrdersItemPropsView, STATUS_COLORS } from './models';
    17→
    18→const MyOrdersCashbackView: FC<MyOrdersItemPropsView> = ({
    19→  handleGoBack,
    20→  myOrders,
    21→  emptyImage,
    22→  formatDate,
    23→  isLoading,
    24→  isError,
    25→  modalizeRefFilters,
    26→  handleOpenFilters,
    27→  handleDetailsOrders,
    28→  handleRefresh,
    29→  filterGroups,
    30→  isRefreshing,
    31→  skeletonCount,
    32→  screenWidth,
    33→}) => {
    34→  return (
    35→    <BasicScreen
    36→      title="Meus pedidos"
    37→      errorButtonOnPress={() => {}}
    38→      hasScroll
    39→      leftIconOnPress={handleGoBack}
    40→      rightIcon="icon-filter-settings"
    41→      rightIconOnPress={handleOpenFilters}
    42→      hasRightIcon={!!myOrders.length}
    43→      scrollViewProps={{
    44→        refreshControl: (
    45→          <RefreshControl
    46→            onRefresh={handleRefresh}
    47→            refreshing={isRefreshing}
    48→            tintColor={theme.colors.BRAND_BASE_01}
    49→          />
    50→        ),
    51→      }}
    52→    >
    53→      {isLoading && (
    54→        <Box width={screenWidth} mt="nano">
    55→          <FlatList
    56→            testID="loading-list-cashback"
    57→            data={Array.from({ length: skeletonCount })}
    58→            keyExtractor={(_, index) => index.toString()}
    59→            scrollEnabled={false}
    60→            renderItem={() => (
    61→              <Skeleton
    62→                testID="loading-orders-cashback"
    63→                width={screenWidth - 64}
    64→                height={150}
    65→                type="light"
    66→                mt="nano"
    67→                mb="nano"
    68→                mr="medium"
    69→                ml="medium"
    70→                borderRadiusTopLeft="half"
    71→              />
    72→            )}
    73→          />
    74→        </Box>
    75→      )}
    76→
    77→      {isError && (
    78→        <ApiError
    79→          testID="orders-cashback-error"
    80→          title="Algo deu errado!"
    81→          subTitle="Por favor, tente mais tarde"
    82→          isLoading={isLoading}
    83→          hasBackToHome={false}
    84→          onPress={handleGoBack}
    85→        />
    86→      )}
    87→
    88→      {!isLoading && !isError && (
    89→        <FlatList
    90→          data={myOrders}
    91→          renderItem={({ item }) => (
    92→            <Box ml="middle" mr="middle" mt="smaller">
    93→              <CardVehicleTags
    94→                vehicleName={item.description}
    95→                icon={item.icon as PropsIconsNameCore}
    96→                title="Valor em pontos"
    97→                titleDescription={String(Math.abs(item.amount))}
    98→                date="Data do resgate"
    99→                dateNumber={formatDate(item.date)}
   100→                statusTitle="Status do pedido"
   101→                status={item.status}
   102→                ghostButtonText="Exibir detalhes"
   103→                onGhostButtonPress={handleDetailsOrders}
   104→                type="extended"
   105→                typeTag={STATUS_COLORS[item.status] ?? 'alert'}
   106→                version="2.0"
   107→              />
   108→            </Box>
   109→          )}
   110→          ListEmptyComponent={() => (
   111→            <Box align="center" pd="innerLarger" justify="center" mt="larger">
   112→              <Image
   113→                resizeMode="contain"
   114→                /* @ts-ignore `source` is not in the props Of `image` ( ͡° ͜ʖ ͡°) */
   115→                source={{ uri: emptyImage }}
   116→                width={80}
   117→                height={80}
   118→              />
   119→
   120→              <Text type="paragraphXXXL" mt="nano">
   121→                Nenhum pedido feito
   122→              </Text>
   123→              <Text type="paragraphLG" align="center" mt="nano">
   124→                Quando você usar seus pontos em pedidos, eles aparecerão aqui.
   125→              </Text>
   126→            </Box>
   127→          )}
   128→        />
   129→      )}
   130→      {filterGroups.length > 0 && (
   131→        <FiltersBottomSheet
   132→          modalizeRef={modalizeRefFilters as RefObject<PropsModalizeRef>}
   133→          filterGroups={filterGroups}
   134→          onApplyFilters={() => {}}
   135→          initialFilters={{}}
   136→        />
   137→      )}
   138→    </BasicScreen>
   139→  );
   140→};
   141→
   142→export default MyOrdersCashbackView;
   143→

